/**
 * SMS notification adapter.
 *
 * Sends notifications via SMS to a phone number derived from the recipient.
 * Implements NotificationAdapter so it can be registered with
 * NotificationService.registerAdapter().
 *
 * Features:
 * - Phone number validation (E.164 format)
 * - Message formatting: composes SMS text from subject and body
 * - Configurable sender number and provider settings
 * - Tracks sent messages in memory for testing/audit
 *
 * NOTE: The recipient field in NotificationPayload is currently an email
 * address for email notifications. For SMS, the recipient should be a phone
 * number in E.164 format (e.g., "+15551234567"). The notification service
 * event handlers currently hardcode channel: 'email' — they will need to be
 * updated to also dispatch SMS notifications with phone numbers as recipients.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsConfig {
  /** The sender phone number or short code (E.164 format). */
  fromNumber: string;
  /** SMS provider name (for future production use). */
  provider?: string;
  /** API key for the SMS provider (for future production use). */
  apiKey?: string;
}

export const defaultSmsConfig: SmsConfig = {
  fromNumber: '+15550000000',
};

/**
 * Represents a formatted SMS message ready for sending.
 */
export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

/**
 * Validates that a string looks like an E.164 phone number.
 * E.164: starts with +, followed by 1-15 digits.
 */
function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{1,14}$/.test(phone);
}

/**
 * Composes the SMS body from a NotificationPayload.
 * SMS messages are length-limited, so we keep it concise:
 * "[Subject] Body"
 */
function composeSmsBody(payload: NotificationPayload): string {
  return `[${payload.subject}] ${payload.body}`;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SmsMessage[] = [];

  constructor(private config: SmsConfig = defaultSmsConfig) {
    if (!isValidPhoneNumber(config.fromNumber)) {
      throw new Error(`Invalid sender phone number: "${config.fromNumber}"`);
    }
  }

  /**
   * Resolve and validate the recipient phone number.
   * Returns the trimmed number or throws if invalid.
   */
  resolveRecipient(recipient: string): string {
    const trimmed = recipient.trim();
    if (!isValidPhoneNumber(trimmed)) {
      throw new Error(`Invalid SMS recipient phone number: "${recipient}"`);
    }
    return trimmed;
  }

  /**
   * Format a NotificationPayload into an SmsMessage containing the
   * to, from, and composed body text.
   */
  formatMessage(payload: NotificationPayload): SmsMessage {
    const to = this.resolveRecipient(payload.recipient);

    return {
      to,
      from: this.config.fromNumber,
      body: composeSmsBody(payload),
    };
  }

  /**
   * Send an SMS notification.
   *
   * Resolves the recipient, formats the message, and delivers it.
   * In production this would call an SMS API provider (e.g., Twilio);
   * currently stores the message in memory.
   */
  async send(payload: NotificationPayload): Promise<void> {
    const message = this.formatMessage(payload);

    this.logger.info(
      `Sending SMS from ${message.from} to ${message.to}: ${payload.subject}`,
    );

    // In production, this is where we'd call the SMS provider API.
    // e.g., await this.smsProvider.send(message);
    this.sentMessages.push(message);
  }

  /**
   * Get all sent SMS messages. Useful for testing.
   */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message history. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

