import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter, defaultSmsConfig } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
  });

  describe('channel', () => {
    it('should report sms channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('constructor', () => {
    it('should accept a valid E.164 phone number', () => {
      expect(() => new SmsAdapter({ fromNumber: '+15551234567' })).not.toThrow();
    });

    it('should accept a valid international number', () => {
      expect(() => new SmsAdapter({ fromNumber: '+442071234567' })).not.toThrow();
    });

    it('should throw for a number without + prefix', () => {
      expect(() => new SmsAdapter({ fromNumber: '15551234567' })).toThrow('Invalid sender phone number');
    });

    it('should throw for an empty string', () => {
      expect(() => new SmsAdapter({ fromNumber: '' })).toThrow('Invalid sender phone number');
    });

    it('should throw for a number with letters', () => {
      expect(() => new SmsAdapter({ fromNumber: '+1555abc4567' })).toThrow('Invalid sender phone number');
    });

    it('should throw for a number starting with +0', () => {
      expect(() => new SmsAdapter({ fromNumber: '+0551234567' })).toThrow('Invalid sender phone number');
    });

    it('should use default config when none provided', () => {
      const defaultAdapter = new SmsAdapter();
      expect(defaultAdapter.channel).toBe('sms');
    });
  });

  describe('resolveRecipient', () => {
    it('should accept a valid E.164 phone number', () => {
      expect(adapter.resolveRecipient('+15551234567')).toBe('+15551234567');
    });

    it('should trim whitespace', () => {
      expect(adapter.resolveRecipient('  +15551234567  ')).toBe('+15551234567');
    });

    it('should throw for a number without + prefix', () => {
      expect(() => adapter.resolveRecipient('15551234567')).toThrow('Invalid SMS recipient phone number');
    });

    it('should throw for an empty string', () => {
      expect(() => adapter.resolveRecipient('')).toThrow('Invalid SMS recipient phone number');
    });

    it('should throw for an email address', () => {
      expect(() => adapter.resolveRecipient('user@example.com')).toThrow('Invalid SMS recipient phone number');
    });
  });

  describe('formatMessage', () => {
    const basePayload: NotificationPayload = {
      recipient: '+15559876543',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
      channel: 'sms',
      type: 'order:confirmation',
    };

    it('should format payload into an SMS message with correct to number', () => {
      const message = adapter.formatMessage(basePayload);
      expect(message.to).toBe('+15559876543');
    });

    it('should include from number from config', () => {
      const message = adapter.formatMessage(basePayload);
      expect(message.from).toBe(defaultSmsConfig.fromNumber);
    });

    it('should use custom from number when configured', () => {
      const customAdapter = new SmsAdapter({ fromNumber: '+18005551234' });
      const message = customAdapter.formatMessage(basePayload);
      expect(message.from).toBe('+18005551234');
    });

    it('should compose body from subject and body', () => {
      const message = adapter.formatMessage(basePayload);
      expect(message.body).toBe('[Order Confirmation: order-1] Your order has been placed. Items: Widget x2. Total: $20.00');
    });

    it('should throw when recipient is invalid', () => {
      const payload: NotificationPayload = {
        ...basePayload,
        recipient: 'not-a-phone',
      };
      expect(() => adapter.formatMessage(payload)).toThrow('Invalid SMS recipient phone number');
    });

    it('should format all notification types correctly', () => {
      const types = [
        'order:confirmation',
        'order:status-update',
        'user:welcome',
        'user:profile-updated',
      ] as const;

      for (const type of types) {
        const payload: NotificationPayload = { ...basePayload, type };
        const message = adapter.formatMessage(payload);
        expect(message.body).toContain(basePayload.body);
      }
    });
  });

  describe('send', () => {
    it('should store message on send', async () => {
      const payload: NotificationPayload = {
        recipient: '+15559876543',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        channel: 'sms',
        type: 'order:confirmation',
      };

      await adapter.send(payload);

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15559876543');
      expect(messages[0]?.from).toBe(defaultSmsConfig.fromNumber);
      expect(messages[0]?.body).toContain('Order Confirmation');
    });

    it('should accumulate multiple messages', async () => {
      const payload1: NotificationPayload = {
        recipient: '+15559876543',
        subject: 'SMS 1',
        body: 'First message',
        channel: 'sms',
        type: 'order:confirmation',
      };
      const payload2: NotificationPayload = {
        recipient: '+15551112222',
        subject: 'SMS 2',
        body: 'Second message',
        channel: 'sms',
        type: 'order:status-update',
      };

      await adapter.send(payload1);
      await adapter.send(payload2);

      expect(adapter.getSentMessages()).toHaveLength(2);
    });

    it('should throw on invalid recipient during send', async () => {
      const payload: NotificationPayload = {
        recipient: 'bad-number',
        subject: 'Test',
        body: 'Test',
        channel: 'sms',
        type: 'order:confirmation',
      };

      await expect(adapter.send(payload)).rejects.toThrow('Invalid SMS recipient phone number');
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should return empty array initially', () => {
      expect(adapter.getSentMessages()).toEqual([]);
    });

    it('should return a copy (not the internal array)', async () => {
      await adapter.send({
        recipient: '+15559876543',
        subject: 'Test',
        body: 'Test',
        channel: 'sms',
        type: 'order:confirmation',
      });

      const first = adapter.getSentMessages();
      const second = adapter.getSentMessages();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });

    it('should clear all sent messages', async () => {
      await adapter.send({
        recipient: '+15559876543',
        subject: 'Test',
        body: 'Test',
        channel: 'sms',
        type: 'order:confirmation',
      });

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('defaultSmsConfig', () => {
    it('should have expected default from number', () => {
      expect(defaultSmsConfig.fromNumber).toBe('+15550000000');
    });
  });
});

